# DeepSpeed pipeline parallelism (conceptual)
import deepspeed

model_engine, _, _, _ = deepspeed.initialize(
    model=model,
    config={
        "pipeline": {
            "stages": 4,               # split across 4 nodes
            "activation_checkpoint_interval": 1,
        },
        "train_micro_batch_size_per_gpu": 4,
        "gradient_accumulation_steps": 8,   # 8 micro-batches per step
        # bubble fraction ≈ (4-1)/(8+4-1) = 3/11 ≈ 27%
    },
)
